import React from 'react';
import './styles/checkbox.css';

export type CheckboxSize    = 'sm' | 'md' | 'lg';
export type CheckboxVariant = 'default' | 'filled' | 'card';
export type CheckboxColor   = 'primary' | 'success' | 'danger' | 'warning';

export interface CheckboxProps {
  checked?: boolean;
  defaultChecked?: boolean;
  indeterminate?: boolean;
  onChange?: (checked: boolean) => void;
  label?: React.ReactNode;
  description?: React.ReactNode;
  size?: CheckboxSize;
  variant?: CheckboxVariant;
  color?: CheckboxColor;
  disabled?: boolean;
  required?: boolean;
  id?: string;
  className?: string;
}

export interface CheckboxGroupProps {
  value?: string[];
  defaultValue?: string[];
  onChange?: (value: string[]) => void;
  orientation?: 'horizontal' | 'vertical';
  disabled?: boolean;
  className?: string;
  children: React.ReactNode;
}

export interface CheckboxGroupItemProps extends Omit<CheckboxProps, 'checked' | 'onChange'> {
  value: string;
}

const GroupContext = React.createContext<{
  value: string[];
  onChange: (v: string, checked: boolean) => void;
  disabled?: boolean;
} | null>(null);

function CheckIcon({ size }: { size: CheckboxSize }) {
  const s = size === 'sm' ? 10 : size === 'lg' ? 14 : 12;
  return (
    <svg width={s} height={s} viewBox="0 0 12 12" fill="none" aria-hidden="true">
      <path d="M2 6l3 3 5-5" stroke="currentColor" strokeWidth="1.8"
        strokeLinecap="round" strokeLinejoin="round"/>
    </svg>
  );
}

function IndeterminateIcon({ size }: { size: CheckboxSize }) {
  const s = size === 'sm' ? 10 : size === 'lg' ? 14 : 12;
  return (
    <svg width={s} height={s} viewBox="0 0 12 12" fill="none" aria-hidden="true">
      <path d="M2.5 6h7" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round"/>
    </svg>
  );
}

export function Checkbox({
  checked,
  defaultChecked,
  indeterminate = false,
  onChange,
  label,
  description,
  size = 'md',
  variant = 'default',
  color = 'primary',
  disabled,
  required,
  id,
  className = '',
}: CheckboxProps) {
  const group = React.useContext(GroupContext);
  const inputRef = React.useRef<HTMLInputElement>(null);
  const isDisabled = disabled || group?.disabled;

  React.useEffect(() => {
    if (inputRef.current) {
      inputRef.current.indeterminate = indeterminate;
    }
  }, [indeterminate]);

  const isChecked = checked !== undefined ? checked : undefined;

  function handleChange(e: React.ChangeEvent<HTMLInputElement>) {
    onChange?.(e.target.checked);
  }

  const cls = [
    'cb-root',
    `cb-size-${size}`,
    `cb-variant-${variant}`,
    `cb-color-${color}`,
    isDisabled ? 'cb-disabled' : '',
    className,
  ].filter(Boolean).join(' ');

  const isCheckedOrIndeterminate = (isChecked || indeterminate);

  return (
    <label className={cls} htmlFor={id}>
      <span className="cb-box-wrap">
        <input
          ref={inputRef}
          type="checkbox"
          id={id}
          checked={isChecked}
          defaultChecked={defaultChecked}
          disabled={!!isDisabled}
          required={required}
          aria-checked={indeterminate ? 'mixed' : isChecked}
          onChange={handleChange}
          className="cb-input"
        />
        <span className={['cb-box', isCheckedOrIndeterminate ? 'cb-checked' : ''].filter(Boolean).join(' ')}>
          {indeterminate
            ? <IndeterminateIcon size={size} />
            : isCheckedOrIndeterminate
              ? <CheckIcon size={size} />
              : null}
        </span>
      </span>
      {(label || description) && (
        <span className="cb-label-wrap">
          {label && <span className="cb-label">{label}{required && <span className="cb-required" aria-hidden="true"> *</span>}</span>}
          {description && <span className="cb-description">{description}</span>}
        </span>
      )}
    </label>
  );
}

export function CheckboxGroup({
  value,
  defaultValue = [],
  onChange,
  orientation = 'vertical',
  disabled,
  className = '',
  children,
}: CheckboxGroupProps) {
  const [internal, setInternal] = React.useState<string[]>(defaultValue);
  const controlled = value !== undefined;
  const current = controlled ? value! : internal;

  function handleChange(v: string, checked: boolean) {
    const next = checked ? [...current, v] : current.filter(i => i !== v);
    if (!controlled) setInternal(next);
    onChange?.(next);
  }

  return (
    <GroupContext.Provider value={{ value: current, onChange: handleChange, disabled }}>
      <div
        className={['cb-group', `cb-group-${orientation}`, className].filter(Boolean).join(' ')}
        role="group"
      >
        {children}
      </div>
    </GroupContext.Provider>
  );
}

export function CheckboxGroupItem({ value, checked, onChange, ...rest }: CheckboxGroupItemProps & { checked?: boolean; onChange?: (c: boolean) => void }) {
  const group = React.useContext(GroupContext);
  const isChecked = group ? group.value.includes(value) : checked;

  function handleChange(c: boolean) {
    group?.onChange(value, c);
    onChange?.(c);
  }

  return <Checkbox {...rest} checked={isChecked} onChange={handleChange} />;
}

export function useCheckbox(initial = false) {
  const [checked, setChecked] = React.useState(initial);
  return { checked, onChange: (c: boolean) => setChecked(c) };
}

export function useCheckboxGroup(initial: string[] = []) {
  const [value, setValue] = React.useState<string[]>(initial);
  return { value, onChange: (v: string[]) => setValue(v) };
}

export default Checkbox;

:root {
  --cb-radius-sm   : 3px;
  --cb-radius-md   : 4px;
  --cb-radius-lg   : 5px;

  --cb-size-sm     : 14px;
  --cb-size-md     : 16px;
  --cb-size-lg     : 20px;

  --cb-border      : 1.5px solid #cbd5e1;
  --cb-border-hover: 1.5px solid #94a3b8;
  --cb-bg          : #ffffff;
  --cb-label-color : #0f172a;
  --cb-desc-color  : #64748b;
  --cb-gap-sm      : 0.5rem;
  --cb-gap-md      : 0.625rem;
  --cb-gap-lg      : 0.75rem;

  --cb-primary     : #6366f1;
  --cb-success     : #22c55e;
  --cb-danger      : #ef4444;
  --cb-warning     : #f59e0b;
}

.cb-root {
  display       : inline-flex;
  align-items   : flex-start;
  gap           : var(--cb-gap-md);
  cursor        : pointer;
  user-select   : none;
}

.cb-root.cb-disabled {
  opacity       : 0.45;
  cursor        : not-allowed;
  pointer-events: none;
}

.cb-input {
  position: absolute;
  opacity : 0;
  width   : 0;
  height  : 0;
  margin  : 0;
}

.cb-box-wrap {
  position   : relative;
  flex-shrink: 0;
  display    : flex;
  align-items: center;
  justify-content: center;
}

.cb-box {
  display        : flex;
  align-items    : center;
  justify-content: center;
  border         : var(--cb-border);
  border-radius  : var(--cb-radius-md);
  background     : var(--cb-bg);
  color          : #ffffff;
  transition     : background 130ms, border-color 130ms;
  pointer-events : none;
}

.cb-root:hover .cb-box {
  border: var(--cb-border-hover);
}

.cb-input:focus-visible + .cb-box {
  outline       : 2px solid var(--cb-accent, var(--cb-primary));
  outline-offset: 2px;
}

.cb-box.cb-checked {
  background  : var(--cb-accent, var(--cb-primary));
  border-color: var(--cb-accent, var(--cb-primary));
}

.cb-label-wrap {
  display       : flex;
  flex-direction: column;
  gap           : 2px;
}

.cb-label {
  font-size  : 0.875rem;
  font-weight: 500;
  color      : var(--cb-label-color);
  line-height: 1.4;
}

.cb-description {
  font-size  : 0.8125rem;
  color      : var(--cb-desc-color);
  line-height: 1.4;
}

.cb-required {
  color: #ef4444;
}

.cb-size-sm .cb-box { width: var(--cb-size-sm); height: var(--cb-size-sm); border-radius: var(--cb-radius-sm); }
.cb-size-md .cb-box { width: var(--cb-size-md); height: var(--cb-size-md); border-radius: var(--cb-radius-md); }
.cb-size-lg .cb-box { width: var(--cb-size-lg); height: var(--cb-size-lg); border-radius: var(--cb-radius-lg); }

.cb-size-sm { gap: var(--cb-gap-sm); }
.cb-size-md { gap: var(--cb-gap-md); }
.cb-size-lg { gap: var(--cb-gap-lg); }

.cb-size-sm .cb-label { font-size: 0.8125rem; }
.cb-size-lg .cb-label { font-size: 0.9375rem; }

.cb-color-primary  { --cb-accent: var(--cb-primary); }
.cb-color-success  { --cb-accent: var(--cb-success); }
.cb-color-danger   { --cb-accent: var(--cb-danger);  }
.cb-color-warning  { --cb-accent: var(--cb-warning); }

.cb-variant-filled .cb-box {
  background: #f1f5f9;
  border    : 1.5px solid transparent;
}
.cb-variant-filled .cb-root:hover .cb-box {
  background: #e2e8f0;
}
.cb-variant-filled .cb-box.cb-checked {
  background  : var(--cb-accent, var(--cb-primary));
  border-color: transparent;
}

.cb-variant-card {
  border       : 0.5px solid #e2e8f0;
  border-radius: 0.625rem;
  padding      : 0.75rem 1rem;
  transition   : border-color 130ms, background 130ms;
  width        : 100%;
}
.cb-variant-card:hover {
  background  : #f8fafc;
  border-color: #cbd5e1;
}
.cb-variant-card:has(.cb-checked) {
  border-color: var(--cb-accent, var(--cb-primary));
  background  : #fafaf9;
}

.cb-group {
  display: flex;
}
.cb-group-vertical   { flex-direction: column; gap: 0.625rem; }
.cb-group-horizontal { flex-direction: row;    gap: 1.25rem; flex-wrap: wrap; align-items: center; }
